#include <string.h>
#include <stdio.h>
#include <stdlib.h>
#include "mmt_lib.h"

//static char* python_script_path = "/opt/mmt/security/python_scripts_and_models/detection_PPC_OCPPFLOWMETER_line_by_line.py";
//static char* model_path = "/opt/mmt/security/python_scripts_and_models/detection_PPC_OCPPFLOWMETER_20240918_YES_IP.pkl";

static char* python_script_path = "/home/pqv/Documents/ocpp/uc4.py";

static bool em_predict_attack

(const char* timestamp, const char* protocol, const char* src_ip,
const char* dst_ip, int src_port, int dst_port,
int length, const char* tcp_flags, int payload_size) 

{
    char buffer[1024];
    char command[2048];

    snprintf(buffer, sizeof(buffer), 
            "timestamp=%s,protocol=%s,src_ip=%s,dst_ip=%s,src_port=%d,dst_port=%d,length=%d,tcp_flags=%s,payload_size=%d", 
            timestamp, protocol, src_ip, dst_ip, src_port, dst_port, length, tcp_flags, payload_size);

    char result[128];
    char last_result[128] = "";
    int prediction;

    // Command to call the Python script
    snprintf(command, sizeof(command),
             "bash -c 'cd /home/pqv/Documents/ocpp/ && source .venv/bin/activate && python3 %s \"%s\"'",
             python_script_path, buffer);

    //snprintf(command, sizeof(command),
    //         "bash -c 'python3 %s %s \"%s\"'",
    //         python_script_path, model_path, buffer);


    FILE *fp = popen(command, "r");
    if (fp == NULL) {
        fprintf(stderr, "Failed to run Python script.\n");
        return -1;
    }

    // Read the output line by line
    while (fgets(result, sizeof(result), fp) != NULL) {
        // Store the current line into `last_result`
        strncpy(last_result, result, sizeof(last_result) - 1);
        last_result[sizeof(last_result) - 1] = '\0';  // Ensure null-termination
    }

    // Close the pipe
    pclose(fp);

    // Check if we captured any output
    if (strlen(last_result) == 0) {
        fprintf(stderr, "No output from Python script.\n");
        return -1;
    }

    // Trim any trailing newline or whitespace from `last_result`
    size_t len = strlen(last_result);
    if (len > 0 && last_result[len - 1] == '\n') {
        last_result[len - 1] = '\0';
    }

    prediction = atoi(last_result);
    return prediction;
}
